from odoo import fields, models


class MailComposeMessage(models.TransientModel):
    _inherit = 'mail.compose.message'

    # currently for log only - qweb generation should be managed by caller
    source_view_id = fields.Many2one(
        'ir.ui.view', 'Generated by (qweb view)',
        index='btree_not_null', ondelete='set null',
    )

    def _prepare_mail_values_static(self):
        # Add 'source_template_id' (based on composer 'template_id') and
        # 'source_view_id' propagation, as part of outgoing message audit
        values = super()._prepare_mail_values_static()
        values['source_template_id'] = self.template_id.id
        values['source_view_id'] = self.source_view_id.id
        return values
